import{_ as e,o as t,c as o,a2 as r}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"F17: 籌碼分佈與法人動態分析 - 財務審計專家報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6239_力成/20260617/F17_籌碼分佈與法人動態分析.md","filePath":"審計報告庫/財務審計/6239_力成/20260617/F17_籌碼分佈與法人動態分析.md"}'),l={name:"審計報告庫/財務審計/6239_力成/20260617/F17_籌碼分佈與法人動態分析.md"};function i(n,a,h,s,d,c){return t(),o("div",null,[...a[0]||(a[0]=[r('<h1 id="f17-籌碼分佈與法人動態分析-財務審計專家報告" tabindex="-1">F17: 籌碼分佈與法人動態分析 - 財務審計專家報告 <a class="header-anchor" href="#f17-籌碼分佈與法人動態分析-財務審計專家報告" aria-label="Permalink to &quot;F17: 籌碼分佈與法人動態分析 - 財務審計專家報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>外資、投信與自營商的近期買賣超動向為何？千張大戶持股比例是否發生結構性變化？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：外資6月淨買超&gt;3.5萬張，投信買盤穩定；千張大戶持穩70.8%無結構變化；法人對力成2026年成長共識度高，籌碼面屬「外資鎖碼型」。</li><li><strong>風險評級</strong>：低</li><li><strong>數據時效</strong>：根據截至2026-06-17最新數據</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p>外資動向：2026年6月（截至6/17）外資淨買超約3,500萬股（+35,000張），其中6/12單日外資買超2,400萬股（24,005張）為最大量，其餘交易日買超500-1,800萬股。投信持倉穩定（約460-470萬股），自營商避險交易量亦呈買超。外資持股從2025年底38.3%在近期進一步攀升。千張大戶結構：12月週數據顯示千張以上持股70.5-70.9%，400張以上78-79%，無顯著變動。散戶（1-999股）人數約4.7萬人（持0.42%），無散戶暴增現象。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="法人買賣超動能" tabindex="-1">法人買賣超動能 <a class="header-anchor" href="#法人買賣超動能" aria-label="Permalink to &quot;法人買賣超動能&quot;">​</a></h3><p>近期外資買超動能來自兩大驅動：(1)2026Q1法說會揭露營收213億（YoY+37.8%）、毛利率19.4%、EPS 2.50元的強勁成績，法人上修全年EPS預估至10元以上；(2)管理層Q2毛利率突破20%的指引、FOPLP良率95%的進度超預期。投信近月買超約1,000-3,150張，部位穩定增加。自營商避險交易同步買超（6月約50-190萬股/日）。三大法人方向一致（均為淨買超），無呈現分歧。</p><h3 id="籌碼鎖定判定" tabindex="-1">籌碼鎖定判定 <a class="header-anchor" href="#籌碼鎖定判定" aria-label="Permalink to &quot;籌碼鎖定判定&quot;">​</a></h3><p>千張大戶70.8%的結構過去12個月來維持穩定，無派發跡象。散戶戶數約8萬戶，扣除千張大戶95人後散戶持有僅約29%。在外資持續加碼、大戶持股不動、散戶未暴增的三重條件下，籌碼面呈現健康的「鎖碼」特徵。若股價在未來1-2個月內因EPS上修而上漲，此鎖碼結構將放大漲幅（籌碼輕、賣壓少）。</p><h3 id="散戶動向檢查" tabindex="-1">散戶動向檢查 <a class="header-anchor" href="#散戶動向檢查" aria-label="Permalink to &quot;散戶動向檢查&quot;">​</a></h3><p>散戶（1-999股）人數12月從46,829人略增至47,595人（+1.6%），但持股市值佔比僅0.43%，無籌碼渙散跡象。融資餘額：未直接取得數據，但以千張大戶佔比極高、外資買超的結構推斷，融資餘額應屬偏低。</p><h2 id="💡-專家評析-多空雙向分析" tabindex="-1">💡 專家評析（多空雙向分析） <a class="header-anchor" href="#💡-專家評析-多空雙向分析" aria-label="Permalink to &quot;💡 專家評析（多空雙向分析）&quot;">​</a></h2><h3 id="🔴-空方觀點-利空風險" tabindex="-1">🔴 空方觀點（利空風險） <a class="header-anchor" href="#🔴-空方觀點-利空風險" aria-label="Permalink to &quot;🔴 空方觀點（利空風險）&quot;">​</a></h3><ol><li><strong>外資若反手賣超的殺傷力</strong>：外資持股38%且近期持續加碼，若全球半導體景氣反轉或力成2026Q2毛利率未達20%預期，外資可能大規模獲利了結，考量流通籌碼僅約22萬張，賣壓將對股價造成顯著衝擊。</li><li><strong>PER已偏高壓縮上漲空間</strong>：當前PER約41倍已處於2025-2026年高位區間（歷史區間8.9-45.1倍），即使2026年EPS達10元，以PER 30-35倍估算合理價約300-350元。籌碼雖佳但估值已充分反映利多。</li></ol><h3 id="🟢-多方觀點-機會可能性" tabindex="-1">🟢 多方觀點（機會可能性） <a class="header-anchor" href="#🟢-多方觀點-機會可能性" aria-label="Permalink to &quot;🟢 多方觀點（機會可能性）&quot;">​</a></h3><ol><li><strong>外資買超具方向性共識</strong>：6月外資單月淨買超逾3.5萬張，方向與投信一致，非散戶追價或短線避險。三大法人同步買超在籌碼面上創造了強勁的下檔支撐。</li><li><strong>大戶鎖碼結構提供韌性</strong>：千張以上70.8%且0質押，意味市場流通在外可交易籌碼有限（&lt;22萬張）。在外資買盤持續下，籌碼供需偏緊，股價有結構性支撐。</li></ol><h3 id="⚖️-綜合權衡" tabindex="-1">⚖️ 綜合權衡 <a class="header-anchor" href="#⚖️-綜合權衡" aria-label="Permalink to &quot;⚖️ 綜合權衡&quot;">​</a></h3><p>力成當前籌碼面屬「外資主導鎖碼型」，法人共識度高、方向一致。主力風險在外資離場時的流動性衝擊，但短期無此跡象。籌碼結構健康，短期內對股價形成支撐。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>計算工具：數據採集器.py (institutional 6239, backer_holding 6239, holding 6239)</li><li>原始數據：FinMind TaiwanStockInstitutionalHolding、TaiwanStockShareholdingSpread</li><li>查詢參數：stock_id=6239, start=2026-04-01, end=2026-06-17</li><li>數據查詢日期：2026-06-17</li></ul>',23)])])}const b=e(l,[["render",i]]);export{u as __pageData,b as default};
